#include <stdio.h>
#include <stdbool.h>
#define MAX_N 500

bool is_safe(int board[MAX_N][MAX_N], int row, int col, int N, int blocked[MAX_N][MAX_N]) {
    for (int i = 0; i < col; i++) {
        if (board[row][i] == 1) return false;
    }
    for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
        if (board[i][j] == 1) return false;
    }
    for (int i = row, j = col; j >= 0; j--) {
        if (board[i][j] == 1) return false;
    }
    for (int i = row, j = col; i < N && j >= 0; i++, j--) {
        if (board[i][j] == 1) return false;
    }
    return true;
}

bool solve_n_queens_util(int board[MAX_N][MAX_N], int col, int N, int blocked[MAX_N][MAX_N]) {
    if (col >= N) return true;
    for (int i = 0; i < N; i++) {
        if (blocked[i][col] == 0 && is_safe(board, i, col, N, blocked)) {
            board[i][col] = 1;
            if (solve_n_queens_util(board, col + 1, N, blocked)) return true;
            board[i][col] = 0;
        }
    }
    return false;
}

void solve_n_queens(int N, int K, int blocked[MAX_N][MAX_N]) {
    int board[MAX_N][MAX_N] = {{0}};
    if (!solve_n_queens_util(board, 0, N, blocked)) {
        printf("No solution exists\n");
        return;
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (board[i][j] == 1) printf("%d ", i + 1);
        }
    }
    printf("\n");
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int blocked[MAX_N][MAX_N] = {{0}};
        for (int i = 0; i < K; i++) {
            int row, col;
            scanf("%d %d", &row, &col);
            blocked[row - 1][col - 1] = 1;
        }
        solve_n_queens(N, K, blocked);
    }
    return 0;
}

