import java.util.Scanner;
public class Main {
    static final int MAX_N = 500;
    public static boolean is_safe(int[][] board, int row, int col, int N, int[][] blocked) {
        for (int i = 0; i < col; i++) {
            if (board[row][i] == 1) return false;
        }
        for (int i = row, j = col; i >= 0 && j >= 0; i--, j--) {
            if (board[i][j] == 1) return false;
        }
        for (int i = row, j = col; j >= 0; j--) {
            if (board[i][j] == 1) return false;
        }
        for (int i = row, j = col; i < N && j >= 0; i++, j--) {
            if (board[i][j] == 1) return false;
        }
        return true;
    }

    public static boolean solve_n_queens_util(int[][] board, int col, int N, int[][] blocked) {
        if (col >= N) return true;
        for (int i = 0; i < N; i++) {
            if (blocked[i][col] == 0 && is_safe(board, i, col, N, blocked)) {
                board[i][col] = 1;
                if (solve_n_queens_util(board, col + 1, N, blocked)) return true;
                board[i][col] = 0;
            }
        }
        return false;
    }

    public static void solve_n_queens(int N, int K, int[][] blocked) {
        int[][] board = new int[N][N];
        if (!solve_n_queens_util(board, 0, N, blocked)) {
            System.out.println("No solution exists");
            return;
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (board[i][j] == 1) System.out.print((i + 1) + " ");
            }
        }
        System.out.println();
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int[][] blocked = new int[N][N];
            for (int i = 0; i < K; i++) {
                int row = scanner.nextInt() - 1;
                int col = scanner.nextInt() - 1;
                blocked[row][col] = 1;
            }
            solve_n_queens(N, K, blocked);
        }
    }
}

